properties.type:
((field: {
    id: string;
    name: string;
}) => boolean) | undefined

properties.description:
Optional format options if values are numbers.

e.g.
     {
       style: "decimal",
       useGrouping: true,
       minimumFractionDigits: 0,
       maximumFractionDigits: 2
     }

     {
       style: "percent",
       useGrouping: true
     }

     {
       style: "currency",
       currency: "EUR",
       currencyDisplay: "symbol"
     }
